concept.syntax:
// Block body — explicit return type
fun add(a: Int, b: Int): Int {
    return a + b
}

// Expression body — return type inferred
fun add(a: Int, b: Int) = a + b

// Default parameter value
fun greet(name: String = "World") = "Hello, $name!"

// Named arguments
greet(name = "Alice")   // explicit label at call site

demo.code:
fun greet(name: String = "World"): String {
    return "Hello, $name!"
}

fun main() {
    val a = greet()
    val b = greet(name = "Alice")
    println(a)
    println(b)
}

